mapper.select:
SELECT f.id, f.user_id AS userId, u.username, f.type, f.title, f.content, f.images, f.status, f.reply, f.target_type AS targetType, f.target_id AS targetId, DATE_FORMAT(f.replied_at, '%Y-%m-%d %H:%i:%s') AS repliedAt, DATE_FORMAT(f.created_at, '%Y-%m-%d %H:%i:%s') AS createdAt, DATE_FORMAT(f.updated_at, '%Y-%m-%d %H:%i:%s') AS updatedAt FROM feedbacks f LEFT JOIN users u ON f.user_id = u.id WHERE 1=1
AND f.type = #{type}
AND f.status = #{status}
ORDER BY f.created_at DESC
